package main

import (
	"fmt"
	"unsafe"
)

// BadLayout has suboptimal field ordering (48 bytes).
type BadLayout struct {
	Active    bool
	Timestamp int64
	Count     int32
	Name      [10]byte
	Enabled   bool
	Value     float64
	Flags     uint16
}

// OptimizedLayout — same fields, packed into 40 bytes (the minimum
// achievable given Go's 8-byte alignment for the int64/float64 pair).
type OptimizedLayout struct {
	[[SLOT first_field]]
	Value     float64
	Count     int32
	Flags     uint16
	Active    bool
	Enabled   bool
	Name      [10]byte
}

// LayoutInfo holds analysis results for a struct.
type LayoutInfo struct {
	TotalSize uintptr
	Offsets   map[string]uintptr
}

// AnalyzeLayout returns size + per-field offsets for the named layout.
func AnalyzeLayout(layoutType string) LayoutInfo {
	info := LayoutInfo{Offsets: map[string]uintptr{}}
	switch layoutType {
	case "bad":
		var b BadLayout
		info.TotalSize = unsafe.Sizeof(b)
		info.Offsets["Active"] = unsafe.Offsetof(b.Active)
		info.Offsets["Timestamp"] = unsafe.Offsetof(b.Timestamp)
		info.Offsets["Count"] = unsafe.Offsetof(b.Count)
		info.Offsets["Name"] = unsafe.Offsetof(b.Name)
		info.Offsets["Enabled"] = unsafe.Offsetof(b.Enabled)
		info.Offsets["Value"] = unsafe.Offsetof(b.Value)
		info.Offsets["Flags"] = unsafe.Offsetof(b.Flags)
	case "optimized":
		var o OptimizedLayout
		info.TotalSize = [[SLOT sizeof_fn]](o)
		info.Offsets["Timestamp"] = [[SLOT offsetof_fn]](o.Timestamp)
		info.Offsets["Value"] = unsafe.Offsetof(o.Value)
		info.Offsets["Count"] = unsafe.Offsetof(o.Count)
		info.Offsets["Flags"] = unsafe.Offsetof(o.Flags)
		info.Offsets["Active"] = unsafe.Offsetof(o.Active)
		info.Offsets["Enabled"] = unsafe.Offsetof(o.Enabled)
		info.Offsets["Name"] = unsafe.Offsetof(o.Name)
	}
	return info
}

func main() {
	bad := AnalyzeLayout("bad")
	opt := AnalyzeLayout("optimized")
	fmt.Printf("BadLayout: %d bytes\n", bad.TotalSize)
	fmt.Printf("OptimizedLayout: %d bytes\n", opt.TotalSize)
	fmt.Printf("Saved: %d bytes\n", [[SLOT diff_calc]])
}
